class RabbitMQConfigError(Exception):
    """Custom exception for RabbitMQ configuration errors."""
    pass


class RabbitMQConfigurator:
    """
    Configures RabbitMQ virtual hosts, users, and permissions via the
    Management HTTP API with strict vhost isolation enforcement.
    """

    # Reserved vhost names that tenants cannot use
    RESERVED_VHOSTS = {"/", "default"}

    # Characters allowed in vhost names (prevent injection)
    VHOST_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.]+$')

    # Characters allowed in usernames
    USERNAME_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.]+$')

    def __init__(
        self,
        host: str = "localhost",
        port: int = 15672,
        admin_user: str = "guest",
        admin_password: str = "guest",
        use_ssl: bool = False,
        verify_ssl: bool = True,
        timeout: int = 30
    ):
        protocol = "https" if use_ssl else "http"
        self.base_url = f"{protocol}://{host}:{port}/api"
        self.auth = (admin_user, admin_password)
        self.timeout = timeout
        self.verify_ssl = verify_ssl
        self.session = requests.Session()
        self.session.auth = self.auth
        self.session.headers.update({"Content-Type": "application/json"})
        self.session.verify = self.verify_ssl

        # Track which vhosts are assigned to which tenants for isolation enforcement
        self._vhost_tenant_map: dict = {}

    def _validate_vhost_name(self, vhost: str) -> None:
        """Validate vhost name to prevent injection and enforce naming rules."""
        if not vhost:
            raise RabbitMQConfigError("Vhost name cannot be empty")
        if vhost in self.RESERVED_VHOSTS:
            raise RabbitMQConfigError(
                f"Vhost name '{vhost}' is reserved and cannot be used for tenants"
            )
        if not self.VHOST_NAME_PATTERN.match(vhost):
            raise RabbitMQConfigError(
                f"Vhost name '{vhost}' contains invalid characters. "
                "Only alphanumeric, underscore, hyphen, and dot are allowed."
            )
        if len(vhost) > 255:
            raise RabbitMQConfigError("Vhost name exceeds maximum length of 255 characters")

    def _validate_username(self, username: str) -> None:
        """Validate username to prevent injection."""
        if not username:
            raise RabbitMQConfigError("Username cannot be empty")
        if not self.USERNAME_PATTERN.match(username):
            raise RabbitMQConfigError(
                f"Username '{username}' contains invalid characters. "
                "Only alphanumeric, underscore, hyphen, and dot are allowed."
            )
        if len(username) > 255:
            raise RabbitMQConfigError("Username exceeds maximum length of 255 characters")

    def _validate_permission_regex(self, pattern: str, field_name: str) -> None:
        """Validate permission regex patterns to prevent overly broad access."""
        if not isinstance(pattern, str):
            raise RabbitMQConfigError(f"Permission {field_name} must be a string")
        # Ensure the pattern is a valid regex
        try:
            re.compile(pattern)
        except re.error as e:
            raise RabbitMQConfigError(
                f"Invalid regex in permission {field_name}: '{pattern}' - {e}"
            )

    def _enforce_vhost_isolation(self, username: str, vhost: str, tenant_name: str) -> None:
        """
        Enforce strict vhost isolation: a user belonging to one tenant
        must NOT be granted permissions on another tenant's vhost.
        """
        if vhost in self._vhost_tenant_map:
            owning_tenant = self._vhost_tenant_map[vhost]
            if owning_tenant != tenant_name:
                raise RabbitMQConfigError(
                    f"ISOLATION VIOLATION: Cannot grant user '{username}' (tenant: '{tenant_name}') "
                    f"access to vhost '{vhost}' which belongs to tenant '{owning_tenant}'. "
                    f"Cross-tenant vhost access is strictly prohibited."
                )

    def _safe_url_encode(self, component: str) -> str:
        """Safely URL-encode a path component."""
        return quote(component, safe='')

    def _api_request(self, method: str, endpoint: str, data: Optional[dict] = None) -> requests.Response:
        """Make an API request with error handling."""
        url = f"{self.base_url}/{endpoint}"
        try:
            response = self.session.request(
                method=method,
                url=url,
                json=data,
                timeout=self.timeout
            )
            return response
        except requests.ConnectionError as e:
            raise RabbitMQConfigError(f"Failed to connect to RabbitMQ API at {url}: {e}")
        except requests.Timeout:
            raise RabbitMQConfigError(f"Request to {url} timed out after {self.timeout}s")
        except requests.RequestException as e:
            raise RabbitMQConfigError(f"API request failed: {e}")

    def check_connection(self) -> bool:
        """Verify connectivity to the RabbitMQ Management API."""
        try:
            response = self._api_request("GET", "overview")
            if response.status_code == 200:
                info = response.json()
                logger.info(
                    f"Connected to RabbitMQ {info.get('rabbitmq_version', 'unknown')} "
                    f"on node {info.get('node', 'unknown')}"
                )
                return True
            elif response.status_code == 401:
                raise RabbitMQConfigError("Authentication failed. Check admin credentials.")
            else:
                raise RabbitMQConfigError(
                    f"Unexpected response from RabbitMQ API: {response.status_code}"
                )
        except RabbitMQConfigError:
            raise
        except Exception as e:
            raise RabbitMQConfigError(f"Connection check failed: {e}")

    def list_vhosts(self) -> list:
        """List all existing virtual hosts."""
        response = self._api_request("GET", "vhosts")
        if response.status_code == 200:
            return response.json()
        raise RabbitMQConfigError(f"Failed to list vhosts: {response.status_code} {response.text}")

    def list_users(self) -> list:
        """List all existing users."""
        response = self._api_request("GET", "users")
        if response.status_code == 200:
            return response.json()
        raise RabbitMQConfigError(f"Failed to list users: {response.status_code} {response.text}")

    def get_user_permissions(self, username: str) -> list:
        """Get all permissions for a specific user across all vhosts."""
        self._validate_username(username)
        encoded_user = self._safe_url_encode(username)
        response = self._api_request("GET", f"users/{encoded_user}/permissions")
        if response.status_code == 200:
            return response.json()
        elif response.status_code == 404:
            return []
        raise RabbitMQConfigError(
            f"Failed to get permissions for user '{username}': {response.status_code}"
        )

    def create_vhost(self, vhost: str, description: str = "", tags: str = "") -> bool:
        """Create a virtual host with validation."""
        self._validate_vhost_name(vhost)

        data = {}
        if description:
            data["description"] = description
        if tags:
            data["tags"] = tags

        encoded_vhost = self._safe_url_encode(vhost)
        response = self._api_request("PUT", f"vhosts/{encoded_vhost}", data)

        if response.status_code in (201, 204):
            logger.info(f"Created vhost: '{vhost}'")
            return True
        elif response.status_code == 409:
            logger.info(f"Vhost '{vhost}' already exists")
            return True
        else:
            raise RabbitMQConfigError(
                f"Failed to create vhost '{vhost}': {response.status_code} {response.text}"
            )

    def delete_vhost(self, vhost: str) -> bool:
        """Delete a virtual host."""
        self._validate_vhost_name(vhost)
        encoded_vhost = self._safe_url_encode(vhost)
        response = self._api_request("DELETE", f"vhosts/{encoded_vhost}")

        if response.status_code == 204:
            logger.info(f"Deleted vhost: '{vhost}'")
            return True
        elif response.status_code == 404:
            logger.warning(f"Vhost '{vhost}' not found")
            return False
        else:
            raise RabbitMQConfigError(
                f"Failed to delete vhost '{vhost}': {response.status_code} {response.text}"
            )

    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        """Create a user with validation and password strength check."""
        self._validate_username(username)

        if len(password) < 12:
            raise RabbitMQConfigError(
                f"Password for user '{username}' is too short. Minimum 12 characters required."
            )

        # Ensure tenant users don't get administrator tag
        if "administrator" in tags.lower():
            raise RabbitMQConfigError(
                f"Cannot assign 'administrator' tag to tenant user '{username}'. "
                "This would break vhost isolation."
            )

        data = {
            "password": password,
            "tags": tags
        }

        encoded_user = self._safe_url_encode(username)
        response = self._api_request("PUT", f"users/{encoded_user}", data)

        if response.status_code in (201, 204):
            logger.info(f"Created user: '{username}' with tags: '{tags}'")
            return True
        else:
            raise RabbitMQConfigError(
                f"Failed to create user '{username}': {response.status_code} {response.text}"
            )

    def delete_user(self, username: str) -> bool:
        """Delete a user."""
        self._validate_username(username)
        encoded_user = self._safe_url_encode(username)
        response = self._api_request("DELETE", f"users/{encoded_user}")

        if response.status_code == 204:
            logger.info(f"Deleted user: '{username}'")
            return True
        elif response.status_code == 404:
            logger.warning(f"User '{username}' not found")
            return False
        else:
            raise RabbitMQConfigError(
                f"Failed to delete user '{username}': {response.status_code} {response.text}"
            )

    def set_permission(
        self,
        username: str,
        vhost: str,
        configure: str = "",
        write: str = "",
        read: str = "",
        tenant_name: str = ""
    ) -> bool:
        """
        Set permissions for a user on a vhost with strict isolation enforcement.

        Args:
            username: The RabbitMQ username
            vhost: The virtual host
            configure: Regex for resources the user can configure (declare/delete)
            write: Regex for resources the user can publish to
            read: Regex for resources the user can consume from
            tenant_name: The tenant this user belongs to (for isolation checks)
        """
        self._validate_username(username)
        self._validate_vhost_name(vhost)
        self._validate_permission_regex(configure, "configure")
        self._validate_permission_regex(write, "write")
        self._validate_permission_regex(read, "read")

        # Enforce vhost isolation
        if tenant_name:
            self._enforce_vhost_isolation(username, vhost, tenant_name)

        data = {
            "configure": configure,
            "write": write,
            "read": read
        }

        encoded_vhost = self._safe_url_encode(vhost)
        encoded_user = self._safe_url_encode(username)
        response = self._api_request(
            "PUT",
            f"permissions/{encoded_vhost}/{encoded_user}",
            data
        )

        if response.status_code in (201, 204):
            logger.info(
                f"Set permissions for user '{username}' on vhost '{vhost}': "
                f"configure='{configure}', write='{write}', read='{read}'"
            )
            return True
        else:
            raise RabbitMQConfigError(
                f"Failed to set permissions for '{username}' on '{vhost}': "
                f"{response.status_code} {response.text}"
            )

    def clear_permission(self, username: str, vhost: str) -> bool:
        """Remove all permissions for a user on a vhost."""
        self._validate_username(username)
        self._validate_vhost_name(vhost)

        encoded_vhost = self._safe_url_encode(vhost)
        encoded_user = self._safe_url_encode(username)
        response = self._api_request(
            "DELETE",
            f"permissions/{encoded_vhost}/{encoded_user}"
        )

        if response.status_code == 204:
            logger.info(f"Cleared permissions for user '{username}' on vhost '{vhost}'")
            return True
        elif response.status_code == 404:
            logger.warning(f"No permissions found for '{username}' on '{vhost}'")
            return False
        else:
            raise RabbitMQConfigError(
                f"Failed to clear permissions: {response.status_code} {response.text}"
            )

    def revoke_all_cross_tenant_permissions(self, tenants: list) -> int:
        """
        Audit and revoke any cross-tenant permissions that may exist.
        Returns the number of permissions revoked.
        """
        revoked_count = 0

        # Build a map of users to their owning tenant
        user_tenant_map = {}
        tenant_vhost_map = {}
        for tenant in tenants:
            tenant_vhost_map[tenant.vhost] = tenant.name
            for username in tenant.users:
                user_tenant_map[username] = tenant.name

        # Check all users' permissions
        try:
            all_users = self.list_users()
        except RabbitMQConfigError:
            logger.error("Failed to list users for cross-tenant audit")
            return 0

        for user_info in all_users:
            username = user_info.get("name", "")
            if username not in user_tenant_map:
                continue  # Skip non-tenant users (e.g., admin)

            owning_tenant = user_tenant_map[username]

            try:
                permissions = self.get_user_permissions(username)
            except RabbitMQConfigError:
                logger.error(f"Failed to get permissions for user '{username}'")
                continue

            for perm in permissions:
                perm_vhost = perm.get("vhost", "")
                if perm_vhost in tenant_vhost_map:
                    vhost_owner = tenant_vhost_map[perm_vhost]
                    if vhost_owner != owning_tenant:
                        logger.warning(
                            f"ISOLATION VIOLATION DETECTED: User '{username}' "
                            f"(tenant: '{owning_tenant}') has permissions on vhost "
                            f"'{perm_vhost}' (tenant: '{vhost_owner}'). Revoking."
                        )
                        try:
                            self.clear_permission(username, perm_vhost)
                            revoked_count += 1
                        except RabbitMQConfigError as e:
                            logger.error(f"Failed to revoke permission: {e}")

        if revoked_count > 0:
            logger.warning(f"Revoked {revoked_count} cross-tenant permission(s)")
        else:
            logger.info("No cross-tenant permission violations found")

        return revoked_count

    def configure_tenant(self, tenant: TenantConfig) -> bool:
        """
        Configure a complete tenant with vhost, users, and permissions.
        Enforces strict vhost isolation.
        """
        logger.info(f"=== Configuring tenant: '{tenant.name}' ===")

        # Validate tenant configuration
        if not tenant.name:
            raise RabbitMQConfigError("Tenant name cannot be empty")

        # Check for isolation violations in the tenant config itself
        if tenant.allowed_vhosts:
            for extra_vhost in tenant.allowed_vhosts:
                if extra_vhost != tenant.vhost and extra_vhost in self._vhost_tenant_map:
                    owning_tenant = self._vhost_tenant_map[extra_vhost]
                    if owning_tenant != tenant.name:
                        raise RabbitMQConfigError(
                            f"ISOLATION VIOLATION in tenant config: Tenant '{tenant.name}' "
                            f"requests access to vhost '{extra_vhost}' owned by "
                            f"tenant '{owning_tenant}'. This is not allowed."
                        )

        # Register vhost ownership
        self._vhost_tenant_map[tenant.vhost] = tenant.name

        # Step 1: Create the vhost
        self.create_vhost(
            tenant.vhost,
            description=f"Vhost for tenant: {tenant.name}"
        )

        # Step 2: Create users and set permissions
        for username, password in tenant.users.items():
            # Create the user (without administrator tag)
            self.create_user(username, password, tags="management")

            # Set permissions - only on the tenant's own vhost
            if username in tenant.permissions:
                perm = tenant.permissions[username]
            else:
                # Default: no permissions (deny by default)
                perm = VhostPermission(configure="", write="", read="")
                logger.warning(
                    f"No explicit permissions defined for user '{username}' "
                    f"on tenant '{tenant.name}'. Defaulting to no access."
                )

            self.set_permission(
                username=username,
                vhost=tenant.vhost,
                configure=perm.configure,
                write=perm.write,
                read=perm.read,
                tenant_name=tenant.name
            )

            # Explicitly ensure user has NO permissions on the default vhost
            # This prevents accidental cross-tenant access via the default vhost
            try:
                self.clear_permission(username, "/")
            except (RabbitMQConfigError, Exception):
                pass  # May not exist, that's fine

        logger.info(f"=== Tenant '{tenant.name}' configured successfully ===")
        return True

    def audit_isolation(self, tenants: list) -> dict:
        """
        Perform a comprehensive audit of vhost isolation.
        Returns a report of any violations found.
        """
        report = {
            "total_tenants": len(tenants),
            "violations": [],
            "clean": True
        }

        user_tenant_map = {}
        tenant_vhost_map = {}

        for tenant in tenants:
            tenant_vhost_map[tenant.vhost] = tenant.name
            for username in tenant.users:
                if username in user_tenant_map:
                    violation = {
                        "type": "duplicate_user",
                        "username": username,
                        "tenants": [user_tenant_map[username], tenant.name],
                        "severity": "HIGH"
                    }
                    report["violations"].append(violation)
                    report["clean"] = False
                user_tenant_map[username] = tenant.name

        # Check for duplicate vhosts
        vhost_count = {}
        for tenant in tenants:
            vhost_count.setdefault(tenant.vhost, []).append(tenant.name)
        for vhost, tenant_names in vhost_count.items():
            if len(tenant_names) > 1:
                violation = {
                    "type": "shared_vhost",
                    "vhost": vhost,
                    "tenants": tenant_names,
                    "severity": "CRITICAL"
                }
                report["violations"].append(violation)
                report["clean"] = False

        # Check actual permissions on the server
        try:
            all_users = self.list_users()
            for user_info in all_users:
                username = user_info.get("name", "")
                if username not in user_tenant_map:
                    continue

                owning_tenant = user_tenant_map[username]
                tags = user_info.get("tags", "")

                # Check if tenant user has administrator tag
                if "administrator" in tags:
                    violation = {
                        "type": "admin_tag_on_tenant_user",
                        "username": username,
                        "tenant": owning_tenant,
                        "severity": "CRITICAL"
                    }
                    report["violations"].append(violation)
                    report["clean"] = False

                # Check permissions
                try:
                    permissions = self.get_user_permissions(username)
                    for perm in permissions:
                        perm_vhost = perm.get("vhost", "")
                        if perm_vhost in tenant_vhost_map:
                            vhost_owner = tenant_vhost_map[perm_vhost]
                            if vhost_owner != owning_tenant:
                                violation = {
                                    "type": "cross_tenant_permission",
                                    "username": username,
                                    "user_tenant": owning_tenant,
                                    "vhost": perm_vhost,
                                    "vhost_tenant": vhost_owner,
                                    "severity": "CRITICAL"
                                }
                                report["violations"].append(violation)
                                report["clean"] = False
                except RabbitMQConfigError:
                    pass
        except RabbitMQConfigError:
            logger.warning("Could not perform live audit - RabbitMQ API unavailable")

        return report


def generate_secure_password(length: int = 24) -> str:
    """Generate a cryptographically secure random password."""
    alphabet = string.ascii_letters + string.digits + "!@#$%^&*"
    # Ensure at least one of each character type
    password = [
        secrets.choice(string.ascii_uppercase),
        secrets.choice(string.ascii_lowercase),
        secrets.choice(string.digits),
        secrets.choice("!@#$%^&*"),
    ]
    password += [secrets.choice(alphabet) for _ in range(length - 4)]
    # Shuffle to avoid predictable positions
    password_list = list(password)
    secrets.SystemRandom().shuffle(password_list)
    return ''.join(password_list)


def build_sample_tenants() -> list:
    """Build sample tenant configurations for demonstration."""
    tenants = []

    # Tenant 1: E-Commerce Application
    ecommerce_password_orders = generate_secure_password()
    ecommerce_password_notifications = generate_secure_password()
    ecommerce_password_readonly = generate_secure_password()

    ecommerce = TenantConfig(
        name="ecommerce",
        vhost="vhost_ecommerce",
        users={
            "ecommerce_orders_svc": ecommerce_password_orders,
            "ecommerce_notifications_svc": ecommerce_password_notifications,
            "ecommerce_monitor": ecommerce_password_readonly,
        },
        permissions={
            # Orders service: can configure, write, and read order-related queues
            "ecommerce_orders_svc": VhostPermission(
                configure="^orders\\.",
                write="^orders\\.",
                read="^orders\\."
            ),
            # Notifications service: can only read from notification queues and write to them
            "ecommerce_notifications_svc": VhostPermission(
                configure="^notifications\\.",
                write="^notifications\\.",
                read="^(notifications\\.|orders\\.completed)"
            ),
            # Monitor: read-only access to all queues in this vhost
            "ecommerce_monitor": VhostPermission(
                configure="",
                write="",
                read=".*"
            ),
        }
    )
    tenants.append(ecommerce)

    # Tenant 2: Analytics Platform
    analytics_password_ingest = generate_secure_password()
    analytics_password_processor = generate_secure_password()

    analytics = TenantConfig(
        name="analytics",
        vhost="vhost_analytics",
        users={
            "analytics_ingest_svc": analytics_password_ingest,
            "analytics_processor_svc": analytics_password_processor,
        },
        permissions={
            "analytics_ingest_svc": VhostPermission(
                configure="^ingest\\.",
                write="^ingest\\.",
                read=""
            ),
            "analytics_processor_svc": VhostPermission(
                configure="^(processed\\.|results\\.)",
                write="^(processed\\.|results\\.)",
                read="^(ingest\\.|processed\\.)"
            ),
        }
    )
    tenants.append(analytics)

    # Tenant 3: IoT Platform
    iot_password_gateway = generate_secure_password()
    iot_password_processor = generate_secure_password()
    iot_password_alerts = generate_secure_password()

    iot = TenantConfig(
        name="iot_platform",
        vhost="vhost_iot",
        users={
            "iot_gateway_svc": iot_password_gateway,
            "iot_processor_svc": iot_password_processor,
            "iot_alerts_svc": iot_password_alerts,
        },
        permissions={
            "iot_gateway_svc": VhostPermission(
                configure="^device\\.",
                write="^device\\.",
                read=""
            ),
            "iot_processor_svc": VhostPermission(
                configure="^(telemetry\\.|commands\\.)",
                write="^(telemetry\\.|commands\\.)",
                read="^(device\\.|telemetry\\.)"
            ),
            "iot_alerts_svc": VhostPermission(
                configure="^alerts\\.",
                write="^alerts\\.",
                read="^(telemetry\\.anomaly|alerts\\.)"
            ),
        }
    )
    tenants.append(iot)

    return tenants


def main():
    """Main entry point for the RabbitMQ configuration script."""
    print("=" * 70)
    print("RabbitMQ Multi-Tenant Configuration Script")
    print("With Strict Vhost Isolation Enforcement")
    print("=" * 70)

    # Initialize the configurator
    configurator = RabbitMQConfigurator(
        host="localhost",
        port=15672,
        admin_user="guest",
        admin_password="guest",
        use_ssl=False
    )

    # Check connection
    try:
        configurator.check_connection()
    except RabbitMQConfigError as e:
        logger.error(f"Cannot connect to RabbitMQ: {e}")
        logger.info("Make sure RabbitMQ is running with the management plugin enabled.")
        logger.info("You can start it with: rabbitmq-plugins enable rabbitmq_management")
        sys.exit(1)

    # Build tenant configurations
    tenants = build_sample_tenants()

    # Configure each tenant
    success_count = 0
    failure_count = 0

    for tenant in tenants:
        try:
            configurator.configure_tenant(tenant)
            success_count += 1
        except RabbitMQConfigError as e:
            logger.error(f"Failed to configure tenant '{tenant.name}': {e}")
            failure_count += 1

    # Audit and revoke any cross-tenant permissions
    print("\n" + "=" * 70)
    print("Running Cross-Tenant Isolation Audit")
    print("=" * 70)

    revoked = configurator.revoke_all_cross_tenant_permissions(tenants)

    # Full audit report
    report = configurator.audit_isolation(tenants)

    print("\n" + "=" * 70)
    print("Isolation Audit Report")
    print("=" * 70)
    print(f"Total tenants: {report['total_tenants']}")
    print(f"Isolation status: {'CLEAN' if report['clean'] else 'VIOLATIONS FOUND'}")

    if report['violations']:
        print(f"\nViolations found: {len(report['violations'])}")
        for v in report['violations']:
            print(f"  [{v['severity']}] {v['type']}: {json.dumps(v, indent=4)}")
    else:
        print("No isolation violations detected.")

    # Summary
    print("\n" + "=" * 70)
    print("Configuration Summary")
    print("=" * 70)
    print(f"Tenants configured successfully: {success_count}")
    print(f"Tenants failed: {failure_count}")
    print(f"Cross-tenant permissions revoked: {revoked}")

    # Print tenant details (without passwords)
    for tenant in tenants:
        print(f"\n  Tenant: {tenant.name}")
        print(f"    Vhost: {tenant.vhost}")
        print(f"    Users: {', '.join(tenant.users.keys())}")
        for username, perm in tenant.permissions.items():
            print(f"    {username} permissions:")
            print(f"      configure: '{perm.configure}'")
            print(f"      write:     '{perm.write}'")
            print(f"      read:      '{perm.read}'")

    # Demonstrate isolation enforcement
    print("\n" + "=" * 70)
    print("Demonstrating Isolation Enforcement")
    print("=" * 70)

    # Try to grant cross-tenant access (should fail)
    try:
        configurator.set_permission(
            username="ecommerce_orders_svc",
            vhost="vhost_analytics",
            configure=".*",
            write=".*",
            read=".*",
            tenant_name="ecommerce"
        )
        print("ERROR: Cross-tenant permission was allowed (this should not happen)")
    except RabbitMQConfigError as e:
        print(f"BLOCKED (expected): {e}")

    # Try to create a user with administrator tag (should fail)
    try:
        configurator.create_user(
            "malicious_admin",
            generate_secure_password(),
            tags="administrator"
        )
        print("ERROR: Administrator tag was allowed (this should not happen)")
    except RabbitMQConfigError as e:
        print(f"BLOCKED (expected): {e}")

    print("\n" + "=" * 70)
    print("Configuration complete. Vhost isolation is enforced.")
    print("=" * 70)

    return 0 if failure_count == 0 else 1


if __name__ == "__main__":
    sys.exit(main())